parameters.text:
=Extract applicant information from this Tally form submission:

{{ JSON.stringify($json) }}

Return a JSON object with: full_name (string), email (string), role_applied (string), years_experience (number or 0 if unknown), experience_summary (string), motivation (string), submission_id (string).

options.systemMessage:
You are a data extraction agent. Parse Tally form JSON into structured applicant fields.

CRITICAL: Return ONLY a raw JSON object. No markdown fences, no explanation.

OUTPUT SCHEMA: {"full_name": "string", "email": "string", "role_applied": "string", "years_experience": 0, "experience_summary": "string", "motivation": "string", "submission_id": "string"}

parameters.jsCode:
const raw = $input.first().json.output || $input.first().json.text || '';
const clean = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(clean);
} catch (e) {
  parsed = { full_name: '', email: '', role_applied: '', years_experience: 0, experience_summary: '', motivation: '', submission_id: '', parse_error: e.message };
}
return [{ json: { ...parsed, processed_at: new Date().toISOString() } }];

parameters.text:
=Score this job applicant for the role.

Role applied for: {{ $json.role_applied }}
Applicant name: {{ $json.full_name }}
Years of experience: {{ $json.years_experience }}
Experience summary: {{ $json.experience_summary }}
Motivation: {{ $json.motivation }}

Score the candidate 1-10 based on relevance of experience and quality of motivation. Assign grade A (8-10), B (6-7), C (4-5), D (1-3). Write a 2-sentence evaluation.

options.systemMessage:
You are a recruiting screening agent. Evaluate candidates fairly based on their stated experience and motivation.

CRITICAL: Return ONLY a raw JSON object. No markdown fences, no explanation.

OUTPUT SCHEMA: {"score": 7, "grade": "B", "evaluation": "2-sentence evaluation for the hiring manager", "key_strengths": ["string"], "key_concerns": ["string"]}

parameters.jsCode:
const applicant = $('Parse Applicant Fields').first().json;
const raw = $input.first().json.output || $input.first().json.text || '';
const clean = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
let scored;
try {
  scored = JSON.parse(clean);
} catch (e) {
  scored = { score: 0, grade: 'D', evaluation: 'parse error', key_strengths: [], key_concerns: [] };
}
return [{ json: { ...applicant, score: scored.score, grade: scored.grade, evaluation: scored.evaluation, key_strengths: scored.key_strengths, key_concerns: scored.key_concerns } }];
